import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  it.todo("should compute base premium for a single sword (100G + 5G processing fee)");
  it.todo("should compute base premium for each main item type (amulet, staff, potion)");
  it.todo("should compute base premium for a single component (25G + 5G fee)");
  it.todo("should compute premium for multiple items summing their base premiums");
  it.todo("should apply component bundle discount (3 alike components at 60G instead of 75G)");
  it.todo("should apply cursed item surcharge of 50%");
  it.todo("should apply high enchantment surcharge of 30% for enchantment level >= 5");
  it.todo("should apply loyalty discount of 20% for customers with >= 2 years");
  it.todo("should apply first insurance surcharge of 10%");
  it.todo("should apply repeat customer discount of 15% on contracts after the first");
  it.todo("should round amounts in MHPCO's favor (ceiling)");
  it.todo("should process a basic claim with 100G deductible");
  it.todo("should cap total payout at twice the insurance sum");
  it.todo("should reimburse enchantment >= 8 damage at 50%");
  it.todo("should fully reimburse dragon material damage");
  it.todo("should handle a quote followed by multiple claims tracking remaining cap");
});

