const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    const basePremium = step.items.reduce(
      (sum: number, item: any) => sum + BASE_PREMIUMS[item.type],
      0
    );
    const premium = basePremium + Math.ceil(basePremium * 0.10) + 5;
    return { premium };
  });
  return { results };
}

content.text:
**Naming Evaluation**:
- `processScenario` — describes what it does: processes a scenario. Clear. Keep.
- `BASE_PREMIUMS` — maps item types to their base premium. Clear. Keep.
- `basePremium` — the sum of base premiums for items. Clear. Keep.
- `premium` — the final computed premium. Clear. Keep.

### Step 2: Calculate Initial APP Mass

```
const BASE_PREMIUMS: Record<string, number> = {  // 4 constants (100, 60, 80, 40), 1 binding (BASE_PREMIUMS), 1 assignment
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export function processScenario(scenario: any): any {  // 1 binding (scenario)
  const results = scenario.steps.map((step: any) => {  // 1 binding (results), 1 assignment, 1 invocation (map), 1 loop (map), 1 binding (step)
    const basePremium = step.items.reduce(  // 1 binding (basePremium), 1 assignment, 1 invocation (reduce), 1 loop (reduce)
      (sum: number, item: any) => sum + BASE_PREMIUMS[item.type],  // 2 bindings (sum, item)
      0  // 1 constant
    );
    const premium = basePremium + Math.ceil(basePremium * 0.10) + 5;  // 1 binding (premium), 1 assignment, 1 invocation (Math.ceil), 2 constants (0.10, 5)
    return { premium };
  });
  return { results };
}
```

Component Count:
- Constants: 7 (100, 60, 80, 40, 0, 0.10, 5) (×1 = 7)
- Bindings: 7 (BASE_PREMIUMS, scenario, results, step, basePremium, sum, item, premium) — actually 8 (×1 = 8)
- Invocations: 3 (map, reduce, Math.ceil) (×2 = 6)
- Conditionals: 0 (×4 = 0)
- Loops: 2 (map, reduce) (×5 = 10)
- Assignments: 3 (BASE_PREMIUMS=, results=, basePremium=, premium=) — actually 4 (×6 = 24)

Total Mass: 7 + 8 + 6 + 0 + 10 + 24 = 55

### Step 3: Apply Simple Design Rules

**Rule 1 - Tests Pass**: ✅ All 2 tests passing

**Rule 2 - Reveals Intent**:
- The magic number `0.10` doesn't explain itself — it's the first insurance surcharge rate. A named constant would help.
- The `5` is the processing fee — also worth naming.
- The expression `basePremium + Math.ceil(basePremium * 0.10) + 5` obscures the business logic.

**Rule 3 - No Duplication**: No duplication yet.

**Rule 4 - Fewest Elements**: The code is relatively lean already.

The best improvement is Rule 2: extract the magic numbers into named constants.

### Step 4: Implement Refactoring

