const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const FIRST_INSURANCE_SURCHARGE = 0.10;
const PROCESSING_FEE = 5;

export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    const basePremium = step.items.reduce(
      (sum: number, item: any) => sum + BASE_PREMIUMS[item.type],
      0
    );
    const premium =
      basePremium + Math.ceil(basePremium * FIRST_INSURANCE_SURCHARGE) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

