    expect(result.results[1].payout).toBe(200);
    expect(result.results[1].remainingCap).toBe(1800);
  });
  it("should cap total payout at twice the insurance sum", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
